const inp=$input.first().json||{};
const strs=[]; (function col(x){if(x==null)return;if(typeof x==='string'){strs.push(x);return;}if(typeof x==='object')for(const v of Object.values(x))col(v);})(inp);
function findStructured(x){if(x&&typeof x==='object'&&!Array.isArray(x)){if(x.ip!==undefined||x.indicator!==undefined||x.target!==undefined)return x;for(const v of Object.values(x)){const r=findStructured(v);if(r)return r;}}return null;}
const a=findStructured(inp)||{};
let ip=String(a.ip||a.indicator||a.target||'').trim();
if(!ip){const m=strs.join(' ').match(/\b\d{1,3}(?:\.\d{1,3}){3}\b/);if(m)ip=m[0];}
return [{json:{ip}}];

const r=$input.first().json||{};
const code=(r.statusCode!==undefined)?r.statusCode:200;
const body=(r.body!==undefined)?r.body:r;
const ip=($('Parse').first().json||{}).ip||'';
if(code===404)return [{json:{ip,found:false,msg:"Shodan: aucune information referencee sur cette IP (ni service expose ni scan connu)"}}];
if(code===401)return [{json:{ip,error:"Shodan: cle invalide ou non autorisee (401)"}}];
if(code===402||code===429)return [{json:{ip,error:"Shodan: quota/credits depasses"}}];
if(code>=400)return [{json:{ip,error:"Shodan HTTP "+code}}];
const b=body||{};
const vulns=b.vulns?(Array.isArray(b.vulns)?b.vulns:Object.keys(b.vulns)):[];
return [{json:{ip, org:b.org||null, isp:b.isp||null, pays:b.country_name||null, asn:b.asn||null,
  ports:b.ports||[], hostnames:b.hostnames||[], tags:b.tags||[],
  vulns:vulns.slice(0,15), nb_vulns:vulns.length, os:b.os||null, last_update:b.last_update||null}}];
